code = """import json
import re

# Load the patent data
data_file = locals()['var_functions.query_db:12']
with open(data_file, 'r') as f:
    all_records = json.load(f)

print('Total records in dataset: ' + str(len(all_records)))

# Sample records to debug
german_samples = []
for i, record in enumerate(all_records[:1000]):
    patents_info = record.get('Patents_info', '')
    
    if 'DE-' in patents_info or 'Germany' in patents_info:
        german_samples.append({
            'index': i,
            'patents_info': patents_info,
            'grant_date': record.get('grant_date', '')
        })

print('Found ' + str(len(german_samples)) + ' German patent samples in first 1000 records')

for sample in german_samples[:5]:
    print('Sample: ' + str(sample))

# Check all German patents in dataset
all_german = []
for record in all_records:
    patents_info = record.get('Patents_info', '')
    grant_date = record.get('grant_date', '')
    
    if 'DE-' in patents_info or 'Germany' in patents_info:
        all_german.append({
            'patents_info': patents_info,
            'grant_date': grant_date
        })

print('\nTotal German patents in entire dataset: ' + str(len(all_german)))

# Check how many have 2019 dates
german_2019 = [p for p in all_german if '2019' in p['grant_date']]
print('German patents with 2019 dates: ' + str(len(german_2019)))

# Show some 2019 samples
if german_2019:
    print('Sample German 2019 patents:')
    for pat in german_2019[:5]:
        print('  ' + str(pat))

print('__RESULT__:')
result = {
    'total_german': len(all_german),
    'german_2019': len(german_2019),
    'samples': german_2019[:3]
}
print(json.dumps(result))"""

